import{_ as a,o,c as r,ag as t}from"./chunks/framework.ePeAWSvT.js";const p=JSON.parse(`{"title":"FAQ","description":"Short answers to common questions about Foldergram's actual scope and behavior.","frontmatter":{"title":"FAQ","description":"Short answers to common questions about Foldergram's actual scope and behavior."},"headers":[],"relativePath":"faq.md","filePath":"faq.md","lastUpdated":1774719654000}`),i={name:"faq.md"};function s(l,e,d,n,h,c){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">â€‹</a></h1><h2 id="is-foldergram-a-cloud-product" tabindex="-1">Is Foldergram a cloud product? <a class="header-anchor" href="#is-foldergram-a-cloud-product" aria-label="Permalink to &quot;Is Foldergram a cloud product?&quot;">â€‹</a></h2><p>No. The current repository is designed for local-only, self-hosted use.</p><h2 id="does-it-upload-or-sync-my-media-anywhere" tabindex="-1">Does it upload or sync my media anywhere? <a class="header-anchor" href="#does-it-upload-or-sync-my-media-anywhere" aria-label="Permalink to &quot;Does it upload or sync my media anywhere?&quot;">â€‹</a></h2><p>No. Originals stay in the configured gallery root.</p><h2 id="does-it-scan-files-directly-during-api-requests" tabindex="-1">Does it scan files directly during API requests? <a class="header-anchor" href="#does-it-scan-files-directly-during-api-requests" aria-label="Permalink to &quot;Does it scan files directly during API requests?&quot;">â€‹</a></h2><p>No. Request handlers read from SQLite and derivative directories. Scanning is a separate service.</p><h2 id="are-files-in-the-gallery-root-indexed" tabindex="-1">Are files in the gallery root indexed? <a class="header-anchor" href="#are-files-in-the-gallery-root-indexed" aria-label="Permalink to &quot;Are files in the gallery root indexed?&quot;">â€‹</a></h2><p>No. Foldergram ignores files placed directly in <code>GALLERY_ROOT</code>.</p><h2 id="do-nested-folders-merge-into-their-parent-album" tabindex="-1">Do nested folders merge into their parent album? <a class="header-anchor" href="#do-nested-folders-merge-into-their-parent-album" aria-label="Permalink to &quot;Do nested folders merge into their parent album?&quot;">â€‹</a></h2><p>No. Nested folders become separate albums when they directly contain supported media.</p><h2 id="how-does-the-app-select-a-folder-s-avatar-or-cover-image" tabindex="-1">How does the app select a folder&#39;s avatar or cover image? <a class="header-anchor" href="#how-does-the-app-select-a-folder-s-avatar-or-cover-image" aria-label="Permalink to &quot;How does the app select a folder&#39;s avatar or cover image?&quot;">â€‹</a></h2><p>By default, Foldergram automatically selects a <code>cover.jpg</code> (or <code>.png</code>, <code>.webp</code>, <code>.avif</code>, <code>.gif</code>) file within the folder if one exists. If no explicit cover file is found, it falls back to the most recent (newest) supported media file in that folder. Admins can also use the &quot;Set as Cover&quot; action from the detail view of any image to set it as the cover without renaming files. Any explicit <code>cover.*</code> files, or any files manually set as the cover via the UI, are hidden from the normal folder grid so they don&#39;t appear as duplicate posts.</p><h2 id="how-do-reserved-stories-folders-work" tabindex="-1">How do reserved stories folders work? <a class="header-anchor" href="#how-do-reserved-stories-folders-work" aria-label="Permalink to &quot;How do reserved stories folders work?&quot;">â€‹</a></h2><p>In the default mode, <code>AppFolder/stories</code> is treated as a story source for that folder:</p><ul><li>direct media inside <code>stories/</code> becomes the avatar story set</li><li>each direct child folder becomes one highlight capsule</li><li>nested folders stay inside that same highlight capsule</li><li>story media is hidden from normal folder, feed, and reels surfaces while this mode is active</li></ul><p>If you already rely on folders literally named <code>stories</code> as normal app folders, open Settings, enable <code>Treat stories folders as normal app folders</code>, and rescan the library.</p><h2 id="are-likes-shared-with-other-users" tabindex="-1">Are likes shared with other users? <a class="header-anchor" href="#are-likes-shared-with-other-users" aria-label="Permalink to &quot;Are likes shared with other users?&quot;">â€‹</a></h2><p>Admin and viewer sessions share SQLite likes for the current library.</p><p>Anonymous public sessions do not write to SQLite likes. They use browser-local favorites only.</p><h2 id="does-foldergram-have-authentication" tabindex="-1">Does Foldergram have authentication? <a class="header-anchor" href="#does-foldergram-have-authentication" aria-label="Permalink to &quot;Does Foldergram have authentication?&quot;">â€‹</a></h2><p>It has optional role-based password protection for the app instance.</p><p>The current implementation supports:</p><ul><li>an <code>admin</code> password with full access</li><li>an optional <code>viewer</code> password with browse-only access and shared likes</li><li>an optional <code>public</code> browse mode with anonymous local favorites and admin unlock</li></ul><p>It still does <strong>not</strong> have per-user accounts or per-user data isolation.</p><h2 id="why-does-the-api-call-posts-images-in-some-fields" tabindex="-1">Why does the API call posts &quot;images&quot; in some fields? <a class="header-anchor" href="#why-does-the-api-call-posts-images-in-some-fields" aria-label="Permalink to &quot;Why does the API call posts &quot;images&quot; in some fields?&quot;">â€‹</a></h2><p>That naming is historical. The current app indexes both images and videos, and several payload fields still use <code>image</code> terminology while carrying mixed media.</p><h2 id="can-foldergram-play-videos-directly-from-the-original-file" tabindex="-1">Can Foldergram play videos directly from the original file? <a class="header-anchor" href="#can-foldergram-play-videos-directly-from-the-original-file" aria-label="Permalink to &quot;Can Foldergram play videos directly from the original file?&quot;">â€‹</a></h2><p>Yes, sometimes. Compatible MP4 originals can be exposed as an optional <code>HD</code> source in the detail player while the generated preview remains the default playback source.</p><h2 id="why-are-thumbnails-or-previews-being-created-while-i-browse" tabindex="-1">Why are thumbnails or previews being created while I browse? <a class="header-anchor" href="#why-are-thumbnails-or-previews-being-created-while-i-browse" aria-label="Permalink to &quot;Why are thumbnails or previews being created while I browse?&quot;">â€‹</a></h2><p>That is expected when <code>DERIVATIVE_MODE=lazy</code>.</p><p>Foldergram still indexes metadata during scans, but it waits to generate missing thumbnails and previews until <code>/thumbnails/...</code> or <code>/previews/...</code> is requested. Once generated, those files are cached on disk for later requests.</p><h2 id="why-would-i-use-regenerate-thumbnails-instead-of-rebuild-library-index" tabindex="-1">Why would I use <code>Regenerate Thumbnails</code> instead of <code>Rebuild Library Index</code>? <a class="header-anchor" href="#why-would-i-use-regenerate-thumbnails-instead-of-rebuild-library-index" aria-label="Permalink to &quot;Why would I use `Regenerate Thumbnails` instead of `Rebuild Library Index`?&quot;">â€‹</a></h2><p>Use <code>Regenerate Thumbnails</code> when the index is still correct and you only want to regenerate feed/profile thumbnails and video poster images. Use <code>Rebuild Library Index</code> when the gallery root changed or the index itself needs to be reset.</p><h2 id="is-the-local-origin-mutation-check-the-same-as-authentication" tabindex="-1">Is the local-origin mutation check the same as authentication? <a class="header-anchor" href="#is-the-local-origin-mutation-check-the-same-as-authentication" aria-label="Permalink to &quot;Is the local-origin mutation check the same as authentication?&quot;">â€‹</a></h2><p>No. It is a separate trust check for browser-triggered mutations.</p><p>Foldergram&#39;s optional admin/viewer/public access control is the auth layer; the local-origin mutation check is an additional safeguard around mutating routes.</p><h2 id="does-the-app-support-remote-multi-user-access" tabindex="-1">Does the app support remote multi-user access? <a class="header-anchor" href="#does-the-app-support-remote-multi-user-access" aria-label="Permalink to &quot;Does the app support remote multi-user access?&quot;">â€‹</a></h2><p>Not as a documented or hardened product target in the current repository.</p><p>The intended scope is still a single-user or shared-household local deployment, not a full multi-user media portal.</p><h2 id="can-anyone-browse-the-app-anonymously" tabindex="-1">Can anyone browse the app anonymously? <a class="header-anchor" href="#can-anyone-browse-the-app-anonymously" aria-label="Permalink to &quot;Can anyone browse the app anonymously?&quot;">â€‹</a></h2><p>Yes, if an admin enables <code>viewer_access_mode=public</code> from Settings.</p><p>In that mode, visitors can browse immediately and keep favorites only in the current browser. Admin-only controls still require unlocking with the admin password.</p>',43)])])}const m=a(i,[["render",s]]);export{p as __pageData,m as default};
